@test_throws DivisionError 1 ÷ 0
@test_nowarn f()          # no warnings

# Group tests
@testset "Economic Dispatch" begin
    @testset "single generator" begin
        @test dispatch([100.0], [10.0], 50.0) == [50.0]
    end
    @testset "merit order" begin
        result = dispatch([100.0, 80.0], [30.0, 10.0], 150.0)
        @test result[2] == 80.0   # cheaper generator first
    end
end
```

Nearly identical to pytest philosophy: self-validating, grouped, descriptive.
